    "mcq": [
      {
        "id": "q1",
        "questionSubtype": "mcq",
        "question": "Which of the following expressions is a valid polynomial in one variable?",
        "options": [
          "A. $x^2 + \\frac{1}{x}$",
          "B. $3x^{\\sqrt{2}} - 5$",
          "C. $4x^3 - 7x + 9$",
          "D. $x^{-2} + 3$"
        ],
        "answer": "C. $4x^3 - 7x + 9$",
        "explanation": "Option C contains only non-negative integer exponents (3, 1, 0). Options A, B, and D contain negative or fractional exponents, which disqualify them as polynomials.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO1"
        ],
        "topicCoverage": [
          "Polynomial Definition"
        ],
        "difficulty": "easy",
        "bloomsLevel": "understanding"
      },
      {
        "id": "q2",
        "questionSubtype": "mcq",
        "question": "What is the degree of the polynomial $P(x) = 5x^4 - x + \\sqrt{3}$?",
        "options": [
          "A. 1",
          "B. 3",
          "C. 4",
          "D. 0"
        ],
        "answer": "C. 4",
        "explanation": "The degree is the highest power of the variable $x$. In this expression, the powers are 4, 1, and 0 (for the constant). The highest is 4.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO2"
        ],
        "topicCoverage": [
          "Degree Identification"
        ],
        "difficulty": "easy",
        "bloomsLevel": "recall"
      },
      {
        "id": "q3",
        "questionSubtype": "mcq",
        "question": "The polynomial $Q(y) = 2y^5 - y^2 + 4$ is classified as a:",
        "options": [
          "A. Monomial",
          "B. Binomial",
          "C. Trinomial",
          "D. Quadrinomial"
        ],
        "answer": "C. Trinomial",
        "explanation": "The expression has three distinct terms separated by addition or subtraction: $2y^5$, $-y^2$, and $+4$. Therefore, it is a trinomial.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO3"
        ],
        "topicCoverage": [
          "Classification by Terms"
        ],
        "difficulty": "easy",
        "bloomsLevel": "understanding"
      }
    ],
    "shortAnswer": [
      {
        "id": "q4",
        "questionSubtype": "veryShortAnswer",
        "question": "Is $\\frac{x}{\\pi} + 1$ a polynomial? Explain briefly.",
        "answer": "Yes, it is a polynomial because dividing by a constant ($\\pi$) does not change the exponent of $x$, which remains 1 (a non-negative integer).",
        "expectedLength": "1-2 clear points",
        "marks": 1,
        "learningOutcomeIds": [
          "LO1"
        ],
        "topicCoverage": [
          "Polynomial Definition"
        ],
        "difficulty": "medium",
        "bloomsLevel": "application"
      },
      {
        "id": "q5",
        "questionSubtype": "veryShortAnswer",
        "question": "What is the degree of the constant polynomial $P(x) = 7$?",
        "answer": "0",
        "expectedLength": "Single number or short phrase",
        "marks": 1,
        "learningOutcomeIds": [
          "LO2"
        ],
        "topicCoverage": [
          "Degree Identification"
        ],
        "difficulty": "easy",
        "bloomsLevel": "recall"
      },
      {
        "id": "q6",
        "questionSubtype": "veryShortAnswer",
        "question": "Classify $R(z) = z^{-2} + 3z$ as a polynomial or non-polynomial.",
        "answer": "Non-polynomial",
        "expectedLength": "Single word or short phrase",
        "marks": 1,
        "learningOutcomeIds": [
          "LO4"
        ],
        "topicCoverage": [
          "Valid vs Invalid Polynomials"
        ],
        "difficulty": "medium",
        "bloomsLevel": "analysis"
      },
      {
        "id": "q7",
        "questionSubtype": "shortAnswer",
        "question": "Identify the degree and classify as monomial, binomial, or trinomial: $P(x) = 2x^3 - x + \\sqrt{5}$.",
        "answer": "Degree: 3. Classification: Trinomial.",
        "expectedLength": "Degree and classification type",
        "marks": 2,
        "rubric": [
          "1 mark for correctly identifying the degree as 3",
          "1 mark for correctly classifying it as a trinomial (3 terms)"
        ],
        "learningOutcomeIds": [
          "LO2",
          "LO3"
        ],
        "topicCoverage": [
          "Degree and Classification"
        ],
        "difficulty": "medium",
        "bloomsLevel": "application"
      },
      {
        "id": "q8",
        "questionSubtype": "shortAnswer",
        "question": "Is $\\sqrt{x} + 5$ a polynomial? Justify your answer using exponent rules.",
        "answer": "No, it is not a polynomial. $\\sqrt{x}$ is equivalent to $x^{1/2}$. Since the exponent $1/2$ is fractional (not a non-negative integer), the expression fails the definition of a polynomial.",
        "expectedLength": "Justification mentioning fractional exponents",
        "marks": 2,
        "rubric": [
          "1 mark for stating it is not a polynomial",
          "1 mark for correctly explaining that $\\sqrt{x}$ implies a fractional exponent ($1/2$)"
        ],
        "learningOutcomeIds": [
          "LO4"
        ],
        "topicCoverage": [
          "Valid vs Invalid Polynomials"
        ],
        "difficulty": "hard",
        "bloomsLevel": "analysis"
      }
    ],
    "longAnswer": [
      {
        "id": "q9",
        "questionSubtype": "longAnswer",
        "question": "Analyze the expression $E(x) = 4x^2 - \\frac{1}{x} + x^{-3}$. Determine if it is a polynomial. If not, identify exactly which terms violate the definition and explain why.",
        "answer": "The expression $E(x)$ is NOT a polynomial. While the term $4x^2$ is valid (exponent 2), the term $-\\frac{1}{x}$ violates the rule because it equals $-x^{-1}$ (negative exponent). Similarly, $x^{-3}$ has a negative exponent. A polynomial requires all variable exponents to be non-negative integers.",
        "expectedLength": "4-5 well-structured points with explanation",
        "marks": 5,
        "rubric": [
          "1 mark for concluding it is not a polynomial",
          "1 mark for identifying $\\frac{1}{x}$ as $x^{-1}$ and explaining the violation",
          "1 mark for identifying $x^{-3}$ and explaining the violation",
          "1 mark for correctly stating the rule regarding non-negative integer exponents",
          "1 mark for clear structure and logical flow"
        ],
        "learningOutcomeIds": [
          "LO4"
        ],
        "topicCoverage": [
          "Valid vs Invalid Polynomials"
        ],
        "difficulty": "hard",
        "bloomsLevel": "analysis"
      },
      {
        "id": "q10",
        "questionSubtype": "longAnswer",
        "question": "Consider the polynomial $P(y) = 3y^4 - 2y + 7$. \n(a) Identify the degree and classify it by the number of terms.\n(b) Evaluate $P(y)$ for $y = -1$.\n(c) Explain how the sign of the coefficient affects the value in step (b).",
        "answer": "(a) Degree: 4. Classification: Trinomial (3 terms).\n(b) Substitution: $P(-1) = 3(-1)^4 - 2(-1) + 7 = 3(1) + 2 + 7 = 3 + 2 + 7 = 12$.\n(c) The coefficient of the linear term is -2. When substituting $y=-1$, we get $-2 \\times (-1)$. The negative sign of the coefficient and the negative value of the variable cancel out to produce a positive contribution (+2) to the total sum.",
        "expectedLength": "4-5 well-structured points with explanation",
        "marks": 5,
        "rubric": [
          "1 mark for correctly identifying degree as 4",
          "1 mark for correctly classifying as trinomial",
          "2 marks for correct evaluation ($3 + 2 + 7 = 12$)",
          "1 mark for clear explanation of how the negative coefficient and negative variable interact"
        ],
        "learningOutcomeIds": [
          "LO2",
          "LO3",
          "LO1"
        ],
        "topicCoverage": [
          "Degree, Classification, and Evaluation"
        ],
        "difficulty": "hard",
        "bloomsLevel": "application"
      }
    ],
    "answerKey": {
      "mcq": [
        {
          "answer": "C. $4x^3 - 7x + 9$",
          "explanation": "Only Option C has non-negative integer exponents.",
